import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { motion } from "framer-motion";
import { useCart } from "../context/CartContext";
import Footer from './Footer';

const SingleProduct = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [quantity, setQuantity] = useState(1);
  const { addToCart } = useCart();
  const [toastMessage, setToastMessage] = useState("");
  const [selectedImage, setSelectedImage] = useState(0);

  useEffect(() => {
    const fetchProduct = async () => {
      try {
        const response = await axios.get(`http://localhost:3000/api/v1/products/${id}`);
        setProduct(response.data);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };
    fetchProduct();
  }, [id]);

  const handleAddToCart = () => {
    addToCart({ ...product, quantity });
    setToastMessage("Added to cart!");
    setTimeout(() => setToastMessage(""), 3000);
  };

  const ProductGallery = ({ images }) => {
    const [selectedImage, setSelectedImage] = useState(images[0]);

    return (
      <div className="flex flex-col md:flex-row gap-4">
        <div className="md:w-1/2">
          <img 
            src={selectedImage} 
            alt={selectedImage} 
            className="w-full h-full object-cover rounded-lg shadow-lg" 
          />
        </div>
        <div className="md:w-1/2 flex flex-col gap-4">
          {images.map((image, index) => (
            <img 
              key={index} 
              src={image} 
              alt={image} 
              className={`w-full h-full object-cover rounded-lg shadow-lg cursor-pointer 
                ${selectedImage === image ? 'border-2 border-red-500' : ''}`} 
              onClick={() => setSelectedImage(image)} 
            />
          ))}
        </div>
      </div>
    );
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-black text-white pt-20">
        <div className="container mx-auto px-4">
          <div className="animate-pulse">
            <div className="h-8 bg-zinc-800 rounded w-1/4 mb-8"></div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
              <div className="aspect-square bg-zinc-800 rounded-2xl"></div>
              <div className="space-y-4">
                <div className="h-8 bg-zinc-800 rounded w-3/4"></div>
                <div className="h-4 bg-zinc-800 rounded w-1/2"></div>
                <div className="h-6 bg-zinc-800 rounded w-1/4 mt-8"></div>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (error || !product) {
    return (
      <div className="min-h-screen bg-black text-white pt-20">
        <div className="container mx-auto px-4 text-center">
          <h2 className="text-2xl text-red-500 mb-4">Error Loading Product</h2>
          <p className="text-gray-400">{error}</p>
          <button 
            onClick={() => navigate(-1)}
            className="mt-8 px-6 py-2 bg-zinc-800 rounded-full hover:bg-zinc-700 transition-colors"
          >
            Go Back
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-white pt-20">
      <div className="container mx-auto px-4 py-12">
        {/* Breadcrumb */}
        <nav className="flex items-center gap-2 text-sm text-gray-400 mb-8">
          <button onClick={() => navigate('/')} className="hover:text-white transition-colors">
            Home
          </button>
          <span>/</span>
          <button onClick={() => navigate('/products')} className="hover:text-white transition-colors">
            Products
          </button>
          <span>/</span>
          <span className="text-white">{product.name}</span>
        </nav>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
          {/* Product Gallery */}
          <div className="space-y-6">
            <ProductGallery images={product.images} />
          </div>

          {/* Product Details */}
          <motion.div 
            className="space-y-8"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.2 }}
          >
            <div>
              <h1 className="text-4xl font-bold mb-4">{product.name}</h1>
              <div className="flex items-center gap-4 text-gray-400 mb-6">
                <span>{product.category?.name}</span>
                <span>•</span>
                <span>Stock: {product.stock}</span>
                {product.stock <= 5 && (
                  <span className="text-yellow-500">• Low Stock</span>
                )}
              </div>
              <div className="flex items-baseline gap-4">
                <span className="text-4xl font-bold">${product.price}</span>
                {product.oldPrice && (
                  <span className="text-xl text-gray-400 line-through">
                    ${product.oldPrice}
                  </span>
                )}
              </div>
            </div>

            <div>
              <h3 className="text-xl font-bold mb-4">Description</h3>
              <p className="text-gray-300 leading-relaxed">
                {product.description}
              </p>
            </div>

            {/* Tags */}
            <div className="flex flex-wrap gap-2">
              {product.tags?.map(tag => (
                <span 
                  key={tag}
                  className="px-3 py-1 bg-zinc-800 rounded-full text-sm text-gray-300"
                >
                  {tag}
                </span>
              ))}
            </div>

            {/* Add to Cart Section */}
            <div className="space-y-6">
              <div className="flex items-center gap-4 p-4 bg-zinc-900 rounded-xl">
                <div className="flex items-center gap-2">
                  <button 
                    onClick={() => setQuantity(Math.max(1, quantity - 1))}
                    className="w-10 h-10 rounded-full bg-zinc-800 hover:bg-zinc-700 
                      flex items-center justify-center text-red-500"
                  >
                    <i className="fas fa-minus"></i>
                  </button>
                  <span className="w-12 text-center">{quantity}</span>
                  <button 
                    onClick={() => setQuantity(quantity + 1)}
                    className="w-10 h-10 rounded-full bg-zinc-800 hover:bg-zinc-700 
                      flex items-center justify-center text-red-500"
                  >
                    <i className="fas fa-plus"></i>
                  </button>
                </div>
                <button
                  onClick={handleAddToCart}
                  className="flex-1 bg-red-500 hover:bg-red-600 h-10 rounded-full 
                    transition-colors font-bold"
                >
                  Add to Cart
                </button>
              </div>
              <button 
                className="w-full h-12 border border-zinc-700 rounded-full 
                  hover:bg-zinc-800 transition-all flex items-center justify-center gap-2"
              >
                <i className="far fa-heart"></i>
                Add to Wishlist
              </button>
            </div>

            {/* Additional Details */}
            <div className="border-t border-zinc-800 pt-8">
              <h3 className="text-xl font-bold mb-4">Product Details</h3>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <p className="text-gray-400">Release Date</p>
                  <p>{new Date(product.dateCreated).toLocaleDateString()}</p>
                </div>
                <div className="space-y-2">
                  <p className="text-gray-400">Scale</p>
                  <p>1:64</p>
                </div>
                <div className="space-y-2">
                  <p className="text-gray-400">Material</p>
                  <p>Die-cast metal</p>
                </div>
                <div className="space-y-2">
                  <p className="text-gray-400">Series</p>
                  <p>{product.category?.name}</p>
                </div>
              </div>
            </div>
          </motion.div>
        </div>
      </div>

      {/* Toast Message */}
      {toastMessage && (
        <div className="fixed top-4 left-1/2 transform -translate-x-1/2 
          bg-green-500 text-white px-6 py-3 rounded shadow-lg z-50">
          {toastMessage}
        </div>
      )}

      <Footer />
    </div>
  );
};

export default SingleProduct;
